patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 2be3b5775292..7671366b8937 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7318,6 +7318,17 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
     return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
+      // If a conditional branch with a constant condition has been folded away
+      // in the VPlan (no corresponding recipe), treat this as an additional
+      // simplification even if the legacy cost-model precomputed and marked
+      // it skipped for cost computation. This allows the assertion comparing
+      // legacy and VPlan cost models to acknowledge structural simplifications
+      // of dead control-flow.
+      if (auto *BI = dyn_cast<BranchInst>(&I)) {
+        if (BI->isConditional() && isa<ConstantInt>(BI->getCondition()) &&
+            !SeenInstrs.contains(&I))
+          return true;
+      }
       return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
     });
   });

